procedure.text:

CREATE OR REPLACE FUNCTION GUID_TO_CHAR_SQL(&&UidId&& uuid)
    RETURNS varchar(36) as $$
    begin

    /*Преобразование GUID в строку с правильным UID-ом */
      RETURN cast(&&UidId&& as varchar(36));
    end;
    $$
    language plpgsql;


CREATE OR REPLACE FUNCTION CHAR_TO_GUID_SQL(&&UidId&& varchar(36))
 RETURNS uuid as $$
 begin

 /*Преобразование GUID в строку с правильным UID-ом */
   RETURN cast(&&UidId&& as uuid);
 end;
 $$
 language plpgsql;
